class Solution {
public:
    int countBinarySubstrings(string s) {
        int count = 0;
        vector<int> prevCount(s.size());
        int prev = 0;
        for (int i = 0; i < s.size(); i++) {
            if (s[i] == '0') {
                prevCount[i] = prev;
                prev = 0;
            } else {
                prevCount[i] = prev + 1;
                prev = prevCount[i];
            }
        }
        for (int i = 1; i < s.size(); i++) {
            count += min(prevCount[i - 1], prevCount[i]);
        }
        return count;
    }
};
